nta.declaration:
// ---- lifecycle states and roles ----
const int Harvested=0, Packaged=1, InTransit=2, Delivered=3, Inspected=4, Rejected=5;
const int producer=0, logistics=1, regulator=2;

// ---- toggles for the sanity checks ----
const bool GUARD_ENABLED   = true;   // set false: governance guard removed
const bool AUDITOR_ENABLED = true;   // set false: auditor recomputation removed

// ---- timing ----
const int FRESH    = 5;   // freshness window: a measurement older than this is stale
const int FINALITY = 3;   // delay before committed events are final and anchorable
const int CAP      = 2;   // bounded number of measurement events (keeps the model finite)

// ---- shared protocol state ----
int[0,5] q = Harvested;   // batch lifecycle state
int[0,2] nmeas = 0;       // valid measurement events admitted
int[0,2] finalized = 0;   // measurement events that reached finality
int[0,2] anchored = 0;    // measurement events accepted as anchored by the auditor
bool illegal   = false;   // STICKY safety flag: an illegal transition/measurement committed
bool badanchor = false;   // STICKY safety flag: a tampered anchor was accepted

// ---- operation request payload (set by Actor, evaluated by Governance) ----
int[0,5] req_next = 0;
int[0,2] req_role = 0;

chan submit;              // Actor  -> Governance
chan finish;             // Reconciler internal step

// ---- lifecycle helper functions (the guard G) ----
int role_of(int tgt) {
    if (tgt == Packaged || tgt == InTransit) return producer;
    if (tgt == Delivered) return logistics;
    return regulator;                       // Inspected, Rejected
}
bool needs_meas(int tgt) { return tgt == Delivered; }   // custody transfer precondition
bool defined_edge(int from, int tgt) {
    if (tgt == Rejected) return from != Inspected && from != Rejected;
    if (tgt == Packaged)  return from == Harvested;
    if (tgt == InTransit) return from == Packaged;
    if (tgt == Delivered) return from == InTransit;
    if (tgt == Inspected) return from == Delivered;
    return false;
}
// Governance evaluation: commit iff the guard passes; else reject (or, guard off, commit illegally).
void govern() {
    bool defd  = defined_edge(q, req_next);
    bool rolek = (req_role == role_of(req_next));
    bool preck = (!needs_meas(req_next) || nmeas >= 1);
    bool guard = defd && rolek && preck;
    if (guard) { q = req_next; }
    else if (!GUARD_ENABLED) { q = req_next; illegal = true; }
    // guard on and !guard: rejected, state unchanged
}
// Measurement admission: valid+fresh accepted; else rejected (or, guard off, admitted illegally).
void admit_measurement(bool valid_and_fresh) {
    if (valid_and_fresh) { if (nmeas < CAP) nmeas++; }
    else if (!GUARD_ENABLED) { if (nmeas < CAP) { nmeas++; illegal = true; } }
}
// Anchoring: honest anchors the true finalized set; byzantine drops one event.
// Auditor accepts iff the anchored count matches the recomputed finalized count.
void anchor(bool byzantine) {
    int claimed = byzantine ? (finalized - 1) : finalized;
    if (claimed == finalized) { anchored = finalized; }          // matches -> accepted
    else if (!AUDITOR_ENABLED) { anchored = claimed; badanchor = true; } // no auditor -> bad accept
    // auditor on and mismatch: flagged, not accepted
}
bool done() {
    return (q == Inspected || q == Rejected) && finalized == nmeas && anchored == nmeas;
}

nta.system:
Act = Actor();
Gov = Governance();
Dev = Device();
Rec = Reconciler();
system Act, Gov, Dev, Rec;
